var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"나도 이렇게까지는 하고 싶지 않았지만.","JPN":"私だってこんなことまでしたくなかったけど。","ENG":"I didn’t want to do this.","TWN":"我也是千百個不願意，"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이젠 돌이킬 수 없어.","JPN":"もう後戻りできない。","ENG":"But there’s no going back now.","TWN":"但頭已經洗下去了。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이건 다 라우라가 잘못한 거야.","JPN":"こうなったのも、全部ラウラが悪いんだからね。","ENG":"It’s all Laura’s fault.","TWN":"都是蘿拉害的啦。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"아, 안녕하세요~~~^^.","JPN":"あ、こんにちは～～(*´▽｀*)","ENG":"Hello! :-D","TWN":"安，安安，大家好～～^^"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"혹시 민초단 그라운드원 지부 공식 커뮤니티 맞나요?","JPN":"あの、ここってチョコミン党グラウンドワン支部の公式コミュニティで合ってますか？","ENG":"Is this the official forum of the MC Club?","TWN":"請問這裡是超薄團的G1分部嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L13_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"아. 네 잘 찾아오셨습니다. 민초 협회 그라운드 원 지부입니다. 반갑습니다.","JPN":"はい、よくいらっしゃいました。 チョウミン協会グラウンドワン支部です。\\nご連絡ありがとうございます。","ENG":"Yes, this is the official forum of MC Society’s Ground One branch. Nice to meet you.","TWN":"是，你好，這裡是超博協會的G1分部"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L14_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"의뢰 때문에 문의하신 건가요?","JPN":"ご依頼のお問い合わせでしょうか？","ENG":"Have you contacted us for a request?","TWN":"請問是關於委託的問題嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>민초 협회</color>?","JPN":"<color=#ffd34c>チョウミン……</color>？","ENG":"<color=#ffd34c>MC Society</color>?","TWN":"<color=#ffd34c>超薄協會</color>？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"민초단 아니었나? 뭐, 협회니까 더 큰 단체겠지?","JPN":"チョコミン党じゃなかったっけ？　協会ってことはもっと大きな団体なのかな？","ENG":"Isn’t it supposed to be the Mint Chocolate Club?","TWN":"我還以為只是個社團而已，沒想到竟然是協會這麼大的團體？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……아, 아무튼!","JPN":"……とにかく！","ENG":"A-anyway!","TWN":"……總之！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"그… 의뢰라고 해야 하나. 하하, 그렇게 거창한 건 아니고요.","JPN":"その……ご依頼というか、あはは、そんな大それたことじゃなくて。","ENG":"Did you say a request? Um, it’s nothing that serious.","TWN":"這個…該說是委託嗎？哈哈，沒有到委託的程度啦。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"제가 이번에 새로운 디저트를 만들었거든요.","JPN":"実は私、今回新しいスイーツを開発したんです。","ENG":"You see, I recently made a new dessert recipe.","TWN":"我有開發一款新的甜點。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"아하, 카페에서 일하시는 분이군요. 그래서요?","JPN":"なるほど、カフェでお仕事されているんですね。続きをお願いできますか？","ENG":"Oh, you work in a cafe? Okay.","TWN":"喔～原來你是在咖啡廳工作嗎？那有什麼事嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L23_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"네, 그런데 신메뉴를 개시한지 며칠 되지도 않았는데, 점장이 인기가 없다면서 내리려고 하는 거예요.","JPN":"そうです。でも、新メニューを出したばかりなのに、店長に売上が悪いから\\n販売終了にすると言われて。","ENG":"It’s only been a few days since we started selling it, but the manager wants to take it off the menu, saying that no one likes it.","TWN":"就是，新甜點才開賣沒多久，店長就說賣不好要停賣。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"저런… 너무하네요.","JPN":"それは……あんまりですね。","ENG":"Ouch, that hurts.","TWN":"怎麼這樣…好壞喔。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L25_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"분명 민트♥위치님이 고심하여 만든 디저트일텐데…….","JPN":"きっとミント♥ウィッチさんが苦労して開発したスイーツでしょうに……","ENG":"You must have worked very hard to make the new dessert, Mint♥Witch...","TWN":"那個甜點是薄荷♥女巫嘔心瀝血的作品吧……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L26_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"점장 분이 주변머리가 없으시네요.","JPN":"気が早い店長ですね。","ENG":"Your manager seems a bit too harsh.","TWN":"是店長自己不會做生意吧？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L27_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"맞아요! 민트 초코 좋아하는 사람이 이렇게나 많은데!!","JPN":"そうなんです！　世の中にはチョコミントが好きな人がこんなにいっぱいいるのに！！","ENG":"I know! There are so many people who love mint chocolate!","TWN":"沒錯！明明就有這麼多人愛薄荷巧克力！！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"제 신메뉴는 아직 홍보가 덜 됐을 뿐이라구요!!","JPN":"私の新メニューはちょっと宣伝が足りないだけなんです！！","ENG":"What my dessert needs is more promotion!","TWN":"我新開發的甜點不賣是因為宣傳不夠好嗎！！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L29_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"하하, 그 마음. 저희도 충분히 공감합니다.","JPN":"はは、そのお気持ち、我々もわかります。","ENG":"Haha, I feel for you.","TWN":"哈哈，你的心情我們非常明白。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L30_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"원래 세상은 선택받은 소수가 다수를 이끌어가는 법이죠.","JPN":"この世界は少数の選ばれし者によって多数が導かれています。","ENG":"Only a few selected people lead the world.","TWN":"這個世界就是獲得揀選的少數人在帶領多數人的。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L31_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"그게 설령 입맛이라고 할지라도요.","JPN":"それが例え、食の好みといえども。","ENG":"And I suppose it's the same with dessert.","TWN":"口味的部分也是。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…이거 봐.","JPN":"……ほらね。","ENG":"I knew it.","TWN":"…就是說。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"역시 민트 초코 좋아하는 사람들끼리는 뭔가 통하는 게 있다니까.","JPN":"やっぱりチョコミント好きな仲間同士、通じるものがあるんだわ。","ENG":"We, the mint chocolate lovers, understand each other.","TWN":"和喜歡薄荷巧克力的人說起話來真是投機。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"아무튼 저희 민초 협회가 뭘 어떻게 도와드리면 될까요?","JPN":"ところで我々チョウミン協会はどのようにサポートすればよろしいでしょうか？","ENG":"Anyway, what can we do for you?","TWN":"那有什麼是我們超博協會可以幫得上忙的嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L37_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"사실, 다음주까지 신메뉴가 안 팔리면 메뉴를 내리기로 점장이랑 약속했거든요.","JPN":"実は、来週までに新メニューの売り上げが伸びなければメニューから外すって\\n店長と約束をしたんです。","ENG":"You see, the manager made me promise that I’d remove my dessert from the menu if no one buys it between now and next week.","TWN":"是這樣的，我和店長打賭，要是到下個禮拜為止，新甜點還是賣不好的話那就下架。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"그래서… 혹시 괜찮다면 민초 협회 분들이 제 신메뉴를 드셔보셨으면 해요.","JPN":"それで……もしよかったら、みなさんに私の新メニューを召し上がっていただきたいんです。","ENG":"So... I was wondering if the MC Society members would like to come and try my new dessert.","TWN":"所以…我想拜託超薄協會的各位，可以來嚐嚐我做的新甜點嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"아하! 마침 잘 됐군요.","JPN":"なるほど！　それならお力添えできそうです。","ENG":"Aha! That would be nice.","TWN":"喔喔～！這麼巧！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L40_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"마침 저희 협회에서도 첫 정모를 준비하고 있던 참이었습니다.","JPN":"ちょうど我々の協会で初となるオフ会を設けようとしていまして。","ENG":"Because we were actually planning our first offline meeting, you see.","TWN":"剛好我們協會準備要辦第一場聚會。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L41_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"인터넷으로만 만나는 사이라서 저희도 협회원들끼리 얼굴을 잘 모르거든요.","JPN":"ネット上での繋がりなので、まだ協会員同士も顔がわからないのです。","ENG":"We’ve only been talking to each other online, so we barely know each other’s faces.","TWN":"因為大家都只在線上聊過天，所以其實都還不清楚會員們的長相呢。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L42_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"오! 정말요? 그럼 특별히 민초연합 분들께는 반값에 드릴게요!","JPN":"えっ、本当ですか？　それでは特別に、協会の皆さんには半額で提供しますね！","ENG":"Really? Then I’ll give you a 50% discount!","TWN":"哇！真的嗎？那我可以替協會的會員打五折！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"민트 초코 좋아하는 사람들끼리 이정도는 해줄 수 있죠!","JPN":"チョコミント好きの仲間にこれくらいのサービスは当然です！","ENG":"Mint chocolate lovers should help each other, right?","TWN":"大家都喜歡薄荷巧克力，就讓我為大家盡一點微薄之力吧！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"좋군요. 그래서 그 신메뉴 이름이 뭐죠?","JPN":"ありがとうございます。その新メニューの名前はなんですか？","ENG":"That’d be great. So what’s the name of the new menu item?","TWN":"好棒，那新甜點的名字是什麼呢？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L45_1","type":"dialog","speaker":"MINT♥WITCH_COUNTERCASE_NULL","text":{"KOREA":"<color=#ffd34c>민트 초코 오믈렛</color>! 제 자신작이니까 기대하셔도 좋아요!","JPN":"<color=#ffd34c>チョコミントオムレツ</color>！　私の自信作なのでご期待ください！","ENG":"It’s the <color=#ffd34c>Mint Chocolate Omelet</color>! It’s my masterpiece!","TWN":"<color=#ffd34c>薄荷巧克力歐姆蛋</color>！這可是我的得意之作！敬請期待吧！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L46_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"민트 초코 오믈렛이라…….","JPN":"チョコミントオムレツですか……","ENG":"Mint Chocolate Omelet?","TWN":"薄荷巧克力歐姆蛋嗎……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L47_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"그런 메뉴라면 아무도 시킬 것 같지 않아서 적절할 것 같네요.","JPN":"そんなメニューなら誰も頼まないだろうし、大丈夫でしょうね。","ENG":"I suppose it will be perfect since no one else would order such a thing.","TWN":"應該不太會有人點這道甜點吧？很適合拿來當作通關密碼呢。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L48_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"좋습니다. 그럼 정모 날짜가 정해지면 따로 연락 드리겠습니다.","JPN":"承知しました。それではオフ会の日時が決まり次第、改めてご連絡申し上げます。","ENG":"Good. Then I’ll let you know when the date is set.","TWN":"好，那聚會的時間確定後我再跟你聯絡。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L50_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"후후, 정모라…….","JPN":"ふふ、オフ会か……","ENG":"Haha, an offline meeting, I like it...","TWN":"呵呵，聚會囉……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINCHO_BOSS_COUNTERCASE_NULL","text":{"KOREA":"……다, 당신들 뭐야?","JPN":"……お、お前たちは何者だ？","ENG":"W-who are you?","TWN":"…你…你們是誰？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"흠~ 흠흠~ 먼저 달걀부터 잔뜩 준비해놓고.","JPN":"フン～フフン～まずは卵をたくさん用意して。","ENG":"*Humming* I need a lot of eggs.","TWN":"哼哼～哼哼～先準備好雞蛋。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그 다음에는 민트 파우더랑~ 밀크 초콜릿을 휙휙 섞어서~","JPN":"その次はミントパウダーと～♪　ミルクチョコレートをさっと混ぜて～♪","ENG":"Then I need mint powder... then mix it with milk chocolate...","TWN":"再加入薄荷粉和牛奶巧克力攪拌均勻～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐야, 오늘따라 묘하게 기분 좋아보이는 표정인데?","JPN":"なんだ、今日はやけにご機嫌だな。","ENG":"You seem very happy today, Yuna.","TWN":"你幹嘛？今天好像心情特別好？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"설마 잊어버린 건 아니겠지?","JPN":"まさか忘れたんじゃないよな？","ENG":"Did you forget?","TWN":"你沒忘記我們的打賭吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"오늘까지 그 저주받은 녹색 계란 부침이 판매량을 못 채울 경우….","JPN":"今日までにあの呪われた薄緑の卵焼きの販売実績が芳しくなかったら……","ENG":"If your accursed green egg fries don’t sell well today...","TWN":"要是今天那個受到詛咒的綠色雞蛋煎餅還是賣不好的話…"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"다시는 민트 초코의 민자도 꺼내지 않기로 했던 약속.","JPN":"二度とチョコミントのチョの字も口にしないという約束を。","ENG":"You will never be allowed to make another mint-related menu item in this cafe, ever.","TWN":"以後就要絕口不提薄荷巧克力！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"후후후, 걱정하지 마. 절대로 그런 일은 없을 테니까.","JPN":"ふふふ。心配しないで、絶対そうはならないから。","ENG":"Haha, don’t worry about it. It won’t happen.","TWN":"呵呵呵，放心吧。你期待的事是絕對不會發生的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……흥.","JPN":"……ふん。","ENG":"Hmpf.","TWN":"……哼。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"무슨 꿍꿍이를 품고 있는지 모르겠지만, 네 생각처럼 자영업이 그렇게 만만하지……","JPN":"何を企んでいるか知らないが、商売というのはそんなに甘くな……","ENG":"I don’t know what you’re up to, but you will soon realize how hard a business can be—","TWN":"不知道你在打什麼歪主意，不過做生意可沒你想得這麼簡單……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어서오세요~","JPN":"いらっしゃいませ！","ENG":"Hello!","TWN":"歡迎光臨～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINCHO_MOB1_COUNTERCASE_NULL","text":{"KOREA":"여기 민트 초코 오믈렛이라는 메뉴 있죠?","JPN":"チョコミントオムレツというメニューはありますか？","ENG":"Do you have a Mint Chocolate Omelet?","TWN":"請問這裡有賣薄荷巧克力歐姆蛋嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……어?","JPN":"……は？","ENG":"Huh?","TWN":"……蛤？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"여기 민트 초코 오믈렛이란 메뉴 있지? 그것 좀 주쇼.","JPN":"チョコミントオムレツってあるよな？　それをくれ。","ENG":"Hey, you have a Mint Chocolate Omelet, right? I want one.","TWN":"這裡有賣薄荷巧克力歐姆蛋吧？請給我一份。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINCHO_MBOSS_COUNTERCASE_NULL","text":{"KOREA":"민트 초코 오믈렛, 하나.","JPN":"チョコミントオムレツ、1つ。","ENG":"One Mint Chocolate Omelet, please.","TWN":"薄荷巧克力歐姆蛋一份。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……이거 뭐야.","JPN":"……どういうことだ。","ENG":"What’s going on?","TWN":"……現在是怎樣。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저희도 민트 초코 오믈렛으로 하나씩 주시겠어요?","JPN":"こちらにもチョコミントオムレツを1つずつお願いします。","ENG":"We would each like a Mint Chocolate Omelet.","TWN":"我們也要一份薄荷巧克力歐姆蛋。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네! 민트 초코 오믈렛 두 개! 잠시만 기다려 주세요~","JPN":"はい！　チョコミントオムレツが2つですね。少々お待ちくださいね！","ENG":"Okay, two Mint Chocolate Omelets. Please wait!","TWN":"好的！薄荷巧克力歐姆蛋二份！請稍等～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"훗훗훗.","JPN":"フッフッフッ。","ENG":"Hehehe.","TWN":"呵呵呵。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"봤지? 봤지, 봤지~? 이제 민초의 위대함을 알겠어, 라우라?","JPN":"ねえねえ見た？ 見た～？　これでもうチョコミントの偉大さがわかったよね？　ラウラ。","ENG":"You see? You see? Do you see the greatness of mint chocolate now, Laura?","TWN":"看到沒有！！知道薄荷巧克力的厲害了吧，蘿拉？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"마, 말도 안돼. 진짜로 이딴 걸 돈 주고 사 먹는 녀석들이 있단 말이야?","JPN":"あ、ありえない。こんなものを金を払ってまで食べたがるやつらが存在するだと？","ENG":"N-no way. There are actually people who are willing to pay for this?","TWN":"怎，怎麼可能？真的有人會花錢買這種東西嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…유행이라는 건 정말 알 것 같으면서도 모르겠군.","JPN":"……流行というのはまったく理解に苦しむものだな。","ENG":"It’s really hard to follow trends these days.","TWN":"…流行還真難懂。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"흥, 이런 거라니! 원래 유행은 따라가는 게 아니라 앞서 나가는 거라고.","JPN":"こんなものってひどい！　流行っていうのは追いかけるんじゃなく、先取りするものだよ。","ENG":"Hah! A trend is something that you make, not follow.","TWN":"哼，什麼叫這種東西！所謂的流行不是盲從，流行是要創造的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"좋았어. 이 메뉴를 발판으로 좀 더 대중적인 민트 초코 디저트를……","JPN":"よし。このメニューをきっかけに、みんなに愛されるチョコミントのスイーツを……","ENG":"Alright. Now I’m going to make another mint chocolate dessert that’s more approachable...","TWN":"很好，那我要繼續創作更大眾化的薄荷巧克力甜點……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"이봐! 아가씨!!","JPN":"おい、店員！","ENG":"Hey, lady!","TWN":"小姐！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……네, 네? 저요?","JPN":"……えっ、えっ？　私ですか？","ENG":"H-huh? Me?","TWN":"……是？你叫我嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"지금 이걸 먹으라고 내놓은 거야!? 오믈렛에서 치약 맛이 나잖아!!","JPN":"こんなのを食えってのか！？　オムレツから歯磨き粉みたいな味がするぞ！！","ENG":"Yeah, what is this? It tastes like toothpaste!","TWN":"這東西是給人吃的嗎？！歐姆蛋怎麼會有牙膏的味道！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINCHO_MOB1_COUNTERCASE_NULL","text":{"KOREA":"아무리 같은 협회원이 일하는 카페라고 해도…… 이건 음식이 너무 심한데요?","JPN":"いくら同じ協会員が働くカフェとはいえ……これは食べ物としてひどすぎませんか？","ENG":"I know you’re one of us... but this food is just horrible!","TWN":"就算要我們來捧會員的場……也不該端出這種東西吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINCHO_MBOSS_COUNTERCASE_NULL","text":{"KOREA":"민트에…… 초코에…… 오믈렛. 끔찍한 혼종.","JPN":"ミントに……チョコに……オムレツ。もはやカオス。","ENG":"Mint... chocolate... in an omelet... It’s just disastrous.","TWN":"薄荷……巧克力……歐姆蛋。驚人的組合。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"이거 어쩔 거야? 난 이런 음식 같지도 않은 음식에 나는 한 푼도 못내.","JPN":"どうしてくれるんだ。俺はこんなものには一銭たりとも払いたくないね。","ENG":"What are you going to do? I ain’t gonna pay for this terrible thing.","TWN":"你說該怎麼辦？這種東西我一口也吃不下！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그렇지만 다들 민초 협회잖아요?","JPN":"で、でもみなさんチョコミント協会の方々ですよね？","ENG":"But you’re all from MC Society, right?","TWN":"可，可是你們不是薄巧協會的嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다들 민트 초코를 좋아하시는게…….","JPN":"みんなチョコミントが好きなんじゃ……","ENG":"You all love mint chocolate...","TWN":"你們不是也喜歡薄荷巧克力嗎……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"민트 초코? 그딴 게 협회랑 무슨 상관이야?","JPN":"チョコミント？　そんなものが協会となんの関係があるんだ？","ENG":"Mint chocolate? What’s it got to do with our Society?","TWN":"薄荷巧克力？薄荷巧克力和協會有什麼關係？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"나는 그냥 대표가 시킨대로 여기서 특정 메뉴를 시켜, 서로의 얼굴을……","JPN":"俺は代表の指示どおり、ここで特定のメニューを頼んで、お互いの顔を……","ENG":"All I heard from the leader was to order a specific dish in this cafe, and check each other’s faces...","TWN":"是會長叫我來我才來的，我們根本連臉都……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"어, 어라…? 얼굴? 설마……!!","JPN":"……えっ、あれ？　顔？　まさか……！！","ENG":"Wait... Check each other’s faces?","TWN":"嗯…？臉？難道……！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN_POLICE"},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"다들 꼼짝마! 경찰이다!","JPN":"動くな！　警察だ！","ENG":"Police! Everybody freeze!","TWN":"警察！不准動！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 경찰!? 여기서 뜬금없이 경찰이 왜 튀어나와?","JPN":"は？　警察！？　なぜ警察がここにいる？","ENG":"Police?! Why are they here?","TWN":"什麼？警察！？警察為什麼會突然出現在這裡？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"너 대체 무슨 짓거리를 한 거야!?","JPN":"汝はいったい何をやらかしたんだ！？","ENG":"What have you done?","TWN":"你到底做了什麼！？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…나, 난 아무것도 안 했어.","JPN":"……わ、私は何もしてないよ。","ENG":"I-I didn’t do anything!","TWN":"…我又沒做什麼。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그냥, 신메뉴를 홍보 했을 뿐인데…….","JPN":"ただ、新メニューを宣伝しただけなのに……","ENG":"All I did was promote my new menu item...","TWN":"我只是宣傳一下新甜點而已……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 손님 분들 주목!!","JPN":"はい、みなさんご注目ください！！","ENG":"Everyone, attention!","TWN":"請各位注意！！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이 중, 민트 초코 오믈렛이라는 메뉴를 시킨 분들은 얌전히 손을 머리 위로 올리고 바닥에 엎드려 주세요.","JPN":"この中でチョコミントオムレツというメニューを頼んだ方は、\\n大人しくうつ伏せになって手を頭の上に乗せてください。","ENG":"Everyone who ordered a Mint Chocolate Omelet; put your hands on your heads, and lie down on the ground.","TWN":"請有點這道薄荷巧克力歐姆蛋的人趴在地上。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이유는 본인들이 더 잘 알고 있겠죠? 암전히 협조해주세요.","JPN":"理由はご自身がおわかりですよね？　大人しく協力してくださいね。","ENG":"You know why we’re here. Do not resist, and cooperate.","TWN":"理由應該不用我說吧？麻煩乖乖配合。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINCHO_MOB1_COUNTERCASE_NULL","text":{"KOREA":"아! 아야! 자, 잠깐만요! 누님, 팔 꺾지 마요.","JPN":"いっ、いたたた！　ちょ、ちょっとお姉さん、腕が痛いです。","ENG":"Ouch! Ouch! Ma’am, you’re hurting my arms!","TWN":"唉唷唷！小力一點！我的手臂要被凹斷啦！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINCHO_MOB2_COUNTERCASE_NULL","text":{"KOREA":"젠장, 역시 함정이었나. 어쩐지 이상하다 했어.","JPN":"くそ！　やっぱり罠だったか。おかしいと思ったんだ。","ENG":"So it was a trap. I thought it was fishy.","TWN":"該死，果然是陷阱，難怪這麼詭異。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINCHO_MBOSS_COUNTERCASE_NULL","text":{"KOREA":"……대표, 대표는 어디있지?","JPN":"……代表、代表はどこだ？","ENG":"Where is our leader?","TWN":"……會長呢？會長在哪裡？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아아, 정모 장소가 바뀐 것 같더라고. 구치소에서 먼저 기다리고 있겠다는데?","JPN":"ああ、オフ会の場所が変わったみたいです。先に拘置所で待ってるらしいですよ。","ENG":"Oh, your offline meeting location has changed. He’s waiting for you in prison.","TWN":"喔喔～你們的聚會地點好像換咧，會長在拘留所等你們。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"디저트는 콩밥으로도 괜찮죠?","JPN":"デザートは臭い飯で構いませんよね？","ENG":"You can enjoy your dessert in the slammer.","TWN":"到牢裡吃牢飯吧！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINCHO_MBOSS_COUNTERCASE_NULL","text":{"KOREA":"그렇군. 벌써 잡힌 건가.","JPN":"そうか、もう捕まったのか。","ENG":"So he’s already caught?","TWN":"原來如此，已經被抓到了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINCHO_MBOSS_COUNTERCASE_NULL","text":{"KOREA":"협회원끼리도 서로 얼굴을 모른다는 걸 역이용하디니……","JPN":"協会員同士でも顔を知らないことが裏目に出たな……","ENG":"You used the fact that we didn’t know each other’s faces...","TWN":"竟然利用會員們都沒見過彼此這一點反將一軍……"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINCHO_MBOSS_COUNTERCASE_NULL","text":{"KOREA":"경찰 쪽도 꽤 하는군.","JPN":"警察もなかなかやるな。","ENG":"You’re pretty good for a cop.","TWN":"警察也蠻有兩下子的嘛。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"협조 감사합니다. 카페 스트레가의 점장님. ……그리고 유나 씨.","JPN":"ご協力ありがとうございました、カフェストレガの店長。……そしてユナさん。","ENG":"Thank you for your cooperation, Cafe Strega management... and Yuna.","TWN":"謝謝你們的配合，史特雷加咖啡廳的店長……還有尤娜也是。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"두 분 덕분에 범죄 조직을 일망타진할 수 있었습니다.","JPN":"お二人のおかげで犯罪組織を一網打尽にすることができました。","ENG":"We caught a gang of criminals thanks to you.","TWN":"多虧有你們的幫忙，我們才能將犯罪組織一網打盡。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"버, 버, 버, 버, 범죄 조직이라고요!?","JPN":"は、は、は、犯罪組織！？","ENG":"A gang of c-c-criminals?!","TWN":"犯，犯，犯，犯，犯罪組織！？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"……네? 모르고 계셨던 건가요?","JPN":"……はい？　知らなかったんですか？","ENG":"Oh, you didn’t know?","TWN":"……什麼？你不知情嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하긴, 아직 세간에 널리 알려진 조직은 아니죠.","JPN":"確かに、世間に知れ渡っている組織ではありませんね。","ENG":"Well, they aren’t very popular among the public.","TWN":"也是啦，畢竟這個組織也還沒出名到人盡皆知。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이 녀석들은 민간 초능력자 협력회. 속칭 민초 협회라고 불려요.","JPN":"こいつらは「超能力者民間協会」。通称、チョウミン協会と呼ばれています。","ENG":"They are called the Mad for Counters Society, a.k.a. MC Society.","TWN":"這個組織叫作超能力者博愛協會，簡稱超博協會。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"미, 민초 협회!?","JPN":"チ、チョウミン協会！？","ENG":"M-MC Society?!","TWN":"超博協會！？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네, 맹목적으로 카운터의 힘을 숭배하는 탓에 카운터 범죄자의 신분 세탁을 돕거나,","JPN":"はい。カウンターの力を崇拝するあまり、カウンター犯罪者の身分の偽装に手を貸したり、","ENG":"Yes. They worship Counters blindly, and they’ve been helping criminal Counters in every way possible.","TWN":"是的，他們是一盲目崇拜制裁者能力的人，因此還替制裁者罪犯辦假身分，"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"불법적인 루트로 자금줄을 대주는 등…… 관리국 골머리 좀 썩인 녀석들이었죠.","JPN":"違法ルートで資金調達をするなど……管理局の頭を悩ませていたやつらでした。","ENG":"Like helping them change their identities, or funding them through illegal means.","TWN":"或是當他們背後的金主等等……是管理局的頭痛人物呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"며칠 전에 녀석들의 대표를 검거했는데.","JPN":"数日前に代表は逮捕されましたが……","ENG":"We apprehended the Society’s leader a few days ago...","TWN":"警方幾天前有抓到他們的會長，"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"민초 협회가 철저하게 점조직으로 운영되고, 구성원 대부분이 방구석 해커들이다보니 다른 협회원의 단서를 잡기가 힘들었어요.","JPN":"チョウミン協会は徹底的に隠れて運営されており、構成員のほとんどが\\n引きこもりのハッカーで、なかなか尻尾がつかめなかったんですよ。","ENG":"But the rest of the members were reclusive hackers who didn’t know each other, so it was very difficult to find them.","TWN":"他們的組織結構嚴密，而且成員大部分是駭客，因此很難找到其他會員的資料。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"……그때, 때마침 운 좋게도!","JPN":"……そんな時に、たまたま！","ENG":"Then, lucky for us!","TWN":"……幸好皇天不負苦心人！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"민초 협회원들이 스트레가라는 카페에서 <color=#ffd34c>이상한 메뉴</color>를 시킬 것이라는 첩보를 얻을 수 있었습니다.","JPN":"チョウミン協会員たちがストレガというカフェで<color=#ffd34c>ヘンテコなメニュー</color>を注文するという情報を入手しました。","ENG":"We got intel that the members of MC Society were going to order a <color=#ffd34c>particular menu</color> at Cafe Strega.","TWN":"我們剛好收到情報說超博協會的人會到史特雷加咖啡廳碰頭，暗號就是一道<color=#ffd34c>奇怪的甜點</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이렇게 현장을 잡을 수 있었던 건, 모두 유나 씨의 재치 덕분이에요.","JPN":"こうして現場を押さえることができたのは、すべてユナさんの機転のおかげです。","ENG":"Thank you, Yuna. We arrested them all at once, thanks to your brilliant idea.","TWN":"我們可以現場逮到犯人都要歸功於尤娜呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…세, 세상에 민트 초코를 사랑하는 협회가 아니었다니.","JPN":"……そ、そんな、チョコミントを愛する協会じゃなかったなんて。","ENG":"S-so they weren’t the Mint Chocolate Club...","TWN":"我…我的天啊，原來他們不是喜歡薄荷巧克力的協會。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네? 방금 뭐라고 하셨죠?","JPN":"はい？　今、なんとおしゃいましたか？","ENG":"Hmm? What did you say?","TWN":"什麼？你剛說什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……예!? 아, 아, 아니에요. 민초 협회 나쁜 놈들!!","JPN":"……はい！？　あ、な、何でもないです。チョウミン協会、悪い人たちですね！","ENG":"Oh, i-it’s nothing. Those evil MC Society criminals!","TWN":"……喔！沒，沒什麼。超博協會的壞蛋！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"…하하, 하하하!","JPN":"……はは、ははは！","ENG":"Haha! Hahaha!","TWN":"…哈哈，哈哈哈！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……그래서 이 빈대떡 같은 게 범죄자도 홀릴 만큼 대단하단 말이야?","JPN":"……それでこの変わったチヂミみたいなものが犯罪者も魅了するほどのメニューってこと？","ENG":"So, this is the dish that even criminals couldn't resist?","TWN":"……所以這個長得像綠豆煎餅的東西很厲害嗎？厲害到可以把犯罪組織唬得一愣一愣的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 그건……!!","JPN":"あっ！　ちょっ……！！","ENG":"Oh, wait!","TWN":"呃！那個……！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……으읍, 쓰다 못해 맵잖아. 대체 이런 걸 왜 먹는 거야.","JPN":"……ううっ。苦いどころか辛いわ。なんでこんなのを食べるわけ？","ENG":"Urgh. It’s bitter... and spicy. What the heck is this?!","TWN":"……噁，這也太辣了吧？到底誰會吃這種東西！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"……하, 하하하.","JPN":"……あ、あはは。","ENG":"Ha, haha...","TWN":"……哈，哈哈哈。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어쨌든 민초 협회 검거에 유나 씨가 큰 기여를 해주셨기 때문에 경찰 본부 측에서 감사패가 나올 겁니다.","JPN":"とにかく、ユナさんはチョウミン協会の逮捕に大きく貢献してくださったので、\\n警察本部から感謝状が贈られる予定です。","ENG":"Well, since you helped us greatly with arresting the criminals, the police will reward you with a plaque of commendation.","TWN":"總之謝謝尤娜幫我們逮到超博協會這個犯罪組織，警方會頒發感謝狀給你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 안 그러셔도 돼요!! 서, 선량한 시민으로서 당연한 일인 걸요!!","JPN":"えっ？　そんなの大丈夫です！！\\nぜ、善良な市民として当たり前のことをしただけですから！","ENG":"Oh, that won’t be necessary! It was my duty as a good citizen.","TWN":"蛤？不用啦！這是身為一位良好市民該做的事！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"기자들도 꽤 오겠죠?","JPN":"贈呈式には記者の方々も来るでしょうね。","ENG":"There will be reporters, too.","TWN":"應該會有很多記者來採訪你喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"용감한 카페 점원, 민초로 민초 잡다. 아마 카페 홍보에도 꽤 도움되지 않을까요?","JPN":"勇敢なカフェの店員、チョコミントでチョウミンを捕まえる。\\nおそらく、カフェの宣伝にも繋がるのでは？","ENG":"A brave cafe employee catches criminals with mint chocolate. It will be great PR for your cafe.","TWN":"勇敢的咖啡廳店員，用薄荷巧克力逮到犯人！說不定可以替咖啡廳宣傳一波喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…받아 와.","JPN":"……もらってこい。","ENG":"Go get the plaque.","TWN":"…你就去領吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"카페에 장식 해두게.","JPN":"カフェに飾っておくから。","ENG":"We’ll hang it on the wall.","TWN":"我會掛在咖啡廳裡。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"……쳇! 아무리 생각해도 아까워. 민초 협회는 전부터 내가 노리고 있었다고!","JPN":"……チッ！　悔しい。チョウミン協会は私が前から目をつけていたのに！","ENG":"Aww, what a shame. I’ve been after MC Society for a while now.","TWN":"……嘖！真可惜，超博協會原本是我的獵物欸！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"이런 아날로그적인 방식으로 허를 찔리다니!! 카페 점원 주제에 꽤 머리가 좋잖아?","JPN":"こんなアナログなやり口にやられるとは！　カフェ店員のくせに頭が切れているじゃないか。","ENG":"I didn’t expect such a classic sting would work on them! She’s pretty smart for a cafe server.","TWN":"竟然用這種傳統的方式逮到犯人！！那個咖啡廳店員腦筋不錯嘛？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그나저나 매버릭. 그래서 결국 민트 초코 오믈렛 먹어 봤어?","JPN":"それはそうとしてマーベリック、結局チョコミントオムレツは食べた？","ENG":"Hey, Maverick. Did you try the Mint Chocolate Omelet?","TWN":"不過麥伯利，結果你有吃到薄荷巧克力歐姆蛋嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"당연하지. 어제 꼬박 두 시간을 기다려서 먹고 왔다고.","JPN":"当然だろ。昨日2時間も待ち続けて食べてきたよ。","ENG":"Sure. I waited for two hours for that.","TWN":"當然有，我昨天可是足足等了二個小時才吃到欸！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"……민트 초코 오믈렛?","JPN":"……チョコミントオムレツ？","ENG":"Mint Chocolate Omelet?","TWN":"……薄荷巧克力歐姆蛋？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"뭐야, 그 괴상한 요리는.","JPN":"なによ、その変な料理は？","ENG":"What’s the heck is that?","TWN":"這是什麼詭異的料理？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"어제 먹었던 아침이 올라 올 것 같은 이름인데?","JPN":"昨日の朝食まで吐き出しそうな名前だけど？","ENG":"It sounds like puke.","TWN":"光是聽到名字就有種反胃感？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"뭐라고? 그걸 여지껏 안 먹어봤다고?","JPN":"何だって？　まだ食べてないのか？","ENG":"What? You haven’t tried it yet?","TWN":"什麼？你竟然還沒吃過？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"아무리 인터넷이 좋아도 가끔은 밖에 나가서 바람도 쐬고 사람도 만나, 사이버 캣.","JPN":"いくらネット世界の居心地がいいとは言え、たまには外の風に当たって人とも会いなよ、サイバーキャット。","ENG":"Cyber Cat, I know you’re in love with cyberspace, but sometimes you have to see real people and get some fresh air, you know?","TWN":"賽博貓，你偶爾也出去接觸一下世界，和人交流一下吧，不要整天待在網路世界裡。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"시끄러워, 적어도 너희들한테 그런 소리 듣고 싶지 않으니까.","JPN":"うるさい。アンタたちには言われたくないわ。","ENG":"Shut up, I don’t want to hear it from you.","TWN":"關你什麼事，才輪不到你們來說我咧。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"아무튼 어땠어, 매버릭? 생각보다 맛있었지?","JPN":"それでどうだった、マーベリック？　案外美味しかったでしょ？","ENG":"So, how was it, Maverick? Pretty good, right?","TWN":"怎麼樣，麥伯利？有比想像中好吃嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"맞아, 처음에는 어떻게 이런 걸 먹나 싶었는데, 먹다보니 자꾸 생각나더라고.","JPN":"ああ、最初はなんじゃこりゃって思ったけど、クセになる味だった。","ENG":"Yeah. It was horrible at first, but it got better and better for some reason.","TWN":"有，一開始我也覺得這種東西是要怎麼吃，結果吃下去後反而會想念呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"후후, 역시 우리 같은 천재들은 시대를 앞서가는 입맛을 타고나는 법이지.","JPN":"ふふ、やはり私たちのように時代を先取りする天才は味覚も違うものだな。","ENG":"Haha, I guess geniuses like us are ahead of our time, even in the field of dessert.","TWN":"呵呵，像我們這種天才，口味果然也是與眾不同。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"맞아, 그런 의미에서 카페 점원. 마녀 코스프레를 하고 있지만 틀림없이 일반인이 아니야.","JPN":"ああ、そういう意味であのカフェの店員。魔女のコスプレなんかしていたけど、\\nきっと一般人じゃない。","ENG":"Yeah. In that sense, I believe the witch-costumed girl at the cafe is not an ordinary person.","TWN":"沒錯，那個咖啡廳店員雖然打扮得像魔女，但我猜她應該不是普通的小老百姓。"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카페 스트레가라…….","JPN":"カフェストレガか……","ENG":"Cafe Strega, huh?","TWN":"史特雷加咖啡廳嗎……"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나중에 심심하면 한 번 들러 볼까?","JPN":"時間があったら後で寄ってみようかな。","ENG":"Maybe I’ll pay a visit next time.","TWN":"下次無聊的話就去看看吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};